import{_ as t,c as e,o as a,V as r}from"./chunks/framework.1sOznGPE.js";const d=JSON.parse('{"title":"为什么需要虚拟DOM","description":"","frontmatter":{},"headers":[],"relativePath":"guide/interview/vue/虚拟DOM/为什么需要虚拟DOM.md","filePath":"guide/interview/vue/虚拟DOM/为什么需要虚拟DOM.md","lastUpdated":1719242077000}'),i={name:"guide/interview/vue/虚拟DOM/为什么需要虚拟DOM.md"},o=r('<h1 id="为什么需要虚拟dom" tabindex="-1">为什么需要虚拟DOM <a class="header-anchor" href="#为什么需要虚拟dom" aria-label="Permalink to &quot;为什么需要虚拟DOM&quot;">​</a></h1><ol><li><p>Virtual DOM 是以 JavaScript 对象为基础而不依赖真实平台环境，<strong>具备跨平台的优势</strong></p></li><li><p><strong>操作原生DOM慢，js运行效率高。</strong></p></li><li><p>Virtual DOM 本质上就是在 JS 和 DOM 之间做了一个缓存。</p></li><li><p><strong>提升渲染性能</strong> Virtual DOM的优势不在于单次的操作，而是在大量、频繁的数据更新下，能够对视图进行合理、高效的更新。</p></li></ol><p><strong>具备跨平台的优势</strong> 由于 Virtual DOM 是以 JavaScript 对象为基础而不依赖真实平台环境，所以使它具有了跨平台的能力，比如说浏览器平台、Weex、Node 等。</p><p>**操作原生DOM慢，js运行效率高。**我们可以将DOM对比操作放在JS层，提高效率。 因为DOM操作的执行速度远不如Javascript的运算速度快，因此，把大量的DOM操作搬运到Javascript中，运用patching算法来计算出真正需要更新的节点，最大限度地减少DOM操作，从而显著提高性能。</p><p>**Virtual DOM 本质上就是在 JS 和 DOM 之间做了一个缓存。**可以类比 CPU 和硬盘，既然硬盘这么慢，我们就在它们之间加个缓存：既然 DOM 这么慢，我们就在它们 JS 和 DOM 之间加个缓存。CPU（JS）只操作内存（Virtual DOM），最后的时候再把变更写入硬盘（DOM）</p><p><strong>提升渲染性能</strong> Virtual DOM的优势不在于单次的操作，而是在大量、频繁的数据更新下，能够对视图进行合理、高效的更新。</p>',6),s=[o];function n(_,p,l,D,O,M){return a(),e("div",null,s)}const u=t(i,[["render",n]]);export{d as __pageData,u as default};
